with open('src/App.jsx', 'r') as f:
    lines = f.readlines()
lines[229] = '  return (<div style={{minHeight:"100vh",background:"#07070F",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px"}}><div style={{background:"#11111A",padding:"40px",borderRadius:"16px",width:"100%",maxWidth:"400px",color:"white"}}><h1 style={{textAlign:"center",marginBottom:"30px"}}>Glowify AI Login</h1>{authError && <div style={{color:"#EF4444",marginBottom:"20px",textAlign:"center"}}>{authError}</div>}<input style={{width:"100%",padding:"12px",marginBottom:"10px",borderRadius:"8px",border:"1px solid #333",background:"#07070F",color:"white"}} type="email" placeholder="Email" value={email} onChange={e=>setEmail(e.target.value)} /><input style={{width:"100%",padding:"12px",marginBottom:"20px",borderRadius:"8px",border:"1px solid #333",background:"#07070F",color:"white"}} type="password" placeholder="Password" value={password} onChange={e=>setPassword(e.target.value)} /><button style={{width:"100%",padding:"12px",borderRadius:"8px",border:"none",background:"#6366F1",color:"white",fontWeight:"bold",cursor:"pointer"}} onClick={handleLogin} disabled={loading}>{loading?"Loading...":"Sign In"}</button></div></div>)\n'
